CREATE OR REPLACE FUNCTION patient.update_patient_timestamp()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = CURRENT_TIMESTAMP;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trigger_update_patient_timestamp
BEFORE UPDATE ON patient.patients
FOR EACH ROW
EXECUTE FUNCTION patient.update_patient_timestamp();

CREATE OR REPLACE FUNCTION notification.create_default_preferences()
RETURNS TRIGGER AS $$
BEGIN
    INSERT INTO notification.preferences (patient_id, tenant_id, email_enabled, sms_enabled, push_enabled, in_app_enabled)
    VALUES (NEW.id, NEW.tenant_id, true, true, true, true);
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trigger_create_default_preferences
AFTER INSERT ON patient.patients
FOR EACH ROW
EXECUTE FUNCTION notification.create_default_preferences();
